import{_ as t,a}from"./chunks/Material Sensor Dialog Dark.WpEanW2j.js";import{_ as i,o as s,c as o,al as r}from"./chunks/framework.-mVGFbqa.js";const k=JSON.parse('{"title":"👤 Material Sensor Dialog","description":"","frontmatter":{},"headers":[],"relativePath":"dialogs/material-sensor-dialog.md","filePath":"dialogs/material-sensor-dialog.md"}'),n={name:"dialogs/material-sensor-dialog.md"};function d(l,e,h,c,p,g){return s(),o("div",null,[...e[0]||(e[0]=[r('<h1 id="👤-material-sensor-dialog" tabindex="-1">👤 Material Sensor Dialog <a class="header-anchor" href="#👤-material-sensor-dialog" aria-label="Permalink to &quot;👤 Material Sensor Dialog&quot;">​</a></h1><div class="note custom-block github-alert"><p class="custom-block-title">NOTE</p><p>🆕 Introduced in version 2.0.0 <br> ✨ <em><strong>Available on Free and Paid mode</strong></em></p></div><h3 id="✨-overview" tabindex="-1">✨ Overview <a class="header-anchor" href="#✨-overview" aria-label="Permalink to &quot;✨ Overview&quot;">​</a></h3><p>The <strong>Material Dialog</strong> is a new interactive component that allows you to view detailed information about a sensor device in a modern Material Design popup.<br> It provides contextual data, related entities, and device information, all inside a responsive dialog optimized for both desktop and mobile (with full-screen mode on phones).</p><p>This dialog gives users a fast and elegant way to check sensor states such as temperature, humidity, motion, or door status without leaving the main Lovelace dashboard.</p><div align="center"><table style="border-radius:28px;overflow:hidden;border-collapse:separate;border-spacing:0;max-width:1000px;"><tbody><tr><td width="50%" align="center" style="padding:24px;background:linear-gradient(135deg, #667eea 0%, #764ba2 100%);"><strong style="color:white;font-size:18px;">☀️ Light Mode</strong><br><br><img src="'+t+'" alt="Dialog Light" style="border-radius:20px;box-shadow:0 8px 32px rgba(0,0,0,0.2);"></td><td width="50%" align="center" style="padding:24px;background:linear-gradient(135deg, #2b5876 0%, #4e4376 100%);"><strong style="color:white;font-size:18px;">🌙 Dark Mode</strong><br><br><img src="'+a+`" alt="Dialog Dark" style="border-radius:20px;box-shadow:0 8px 32px rgba(0,0,0,0.4);"></td></tr></tbody></table></div><h2 id="✅-how-to-open-the-material-dialog" tabindex="-1">✅ How to Open the Material Dialog <a class="header-anchor" href="#✅-how-to-open-the-material-dialog" aria-label="Permalink to &quot;✅ How to Open the Material Dialog&quot;">​</a></h2><h3 id="🆓-free-version" tabindex="-1">🆓 Free Version <a class="header-anchor" href="#🆓-free-version" aria-label="Permalink to &quot;🆓 Free Version&quot;">​</a></h3><p>To open the Material Dialog, simply use the <code>material-button-card</code> with the attribute:</p><div class="language-yaml vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">yaml</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">use_default_toggle</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">true</span></span></code></pre></div><p>When the button is configured with one of the supported sensor types, tapping it will automatically open the <strong>Material Dialog</strong> with detailed information.</p><p><strong>Example Configuration</strong></p><div class="language-yaml vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">yaml</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">type</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">custom:material-button-card</span></span>
<span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">control_type</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">generic</span></span>
<span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">entity</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">binary_sensor.motion_livingroom</span></span>
<span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">use_default_icon</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">true</span></span>
<span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">use_default_toggle</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">true</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"> # &lt;-- Required in the Free version!</span></span></code></pre></div><p>When the entity corresponds to a supported sensor (e.g., motion, door, temperature, humidity), the dialog will open automatically upon tap.</p><h4 id="i️-action-trigger" tabindex="-1">ℹ️ Action trigger <a class="header-anchor" href="#i️-action-trigger" aria-label="Permalink to &quot;ℹ️ Action trigger&quot;">​</a></h4><table tabindex="0"><thead><tr><th>Card Type</th><th>Action Type</th><th>Sensor</th></tr></thead><tbody><tr><td><code>material-button-card</code></td><td><code>tap_action</code></td><td><code>door</code>, <code>motion</code>, <code>temperature</code></td></tr></tbody></table><h3 id="🪄-pro-ultimate-version" tabindex="-1">🪄 <strong>Pro &amp; Ultimate Version</strong> <a class="header-anchor" href="#🪄-pro-ultimate-version" aria-label="Permalink to &quot;🪄 **Pro &amp; Ultimate Version**&quot;">​</a></h3><p>In the paid versions, automatic actions are the <strong>default</strong> behavior.</p><ul><li>If you <strong>do not</strong> define a <code>tap_action</code> or the <code>hold_action</code>, the <code>custom-more-info</code> action will be executed on tap.</li><li>You do not need to use <code>use_default_toggle</code>, which is deprecated in these versions.</li></ul><p><em>Example (Pro/Ultimate): <code>more-info</code> is automatic</em></p><div class="language-yaml vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">yaml</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">type</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">custom:material-button-card</span></span>
<span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">control_type</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">generic</span></span>
<span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">entity</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">binary_sensor.motion_livingroom</span></span>
<span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">use_default_icon</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">true</span></span></code></pre></div><h4 id="i️-action-trigger-1" tabindex="-1">ℹ️ Action trigger <a class="header-anchor" href="#i️-action-trigger-1" aria-label="Permalink to &quot;ℹ️ Action trigger&quot;">​</a></h4><table tabindex="0"><thead><tr><th>Action Type</th><th>Card Type</th><th>Sensor (By Device Class)</th></tr></thead><tbody><tr><td><code>tap_action</code></td><td><code>material-button-card</code>, <code>material-options-card</code>, <code>material-circle-progress-card</code></td><td><code>door</code>, <code>motion</code>, <code>temperature</code>, <code>presence</code>, <code>occupancy</code></td></tr></tbody></table><div class="note custom-block github-alert"><p class="custom-block-title">NOTE</p><p>🧠 <em>More sensor types may be added in future updates.</em></p></div><h2 id="⚙️-supported-device-classes" tabindex="-1">⚙️ Supported Device Classes <a class="header-anchor" href="#⚙️-supported-device-classes" aria-label="Permalink to &quot;⚙️ Supported Device Classes&quot;">​</a></h2><h3 id="🆓-free-version-1" tabindex="-1">🆓 Free Version <a class="header-anchor" href="#🆓-free-version-1" aria-label="Permalink to &quot;🆓 Free Version&quot;">​</a></h3><p>The <strong>Material Dialog</strong> is currently compatible with the following device types:</p><table tabindex="0"><thead><tr><th>Device Type</th><th>Description</th></tr></thead><tbody><tr><td><code>motion</code></td><td>Motion or presence sensors. Displays active/inactive state with animated feedback.</td></tr><tr><td><code>door</code></td><td>Door or window contact sensors. Shows open/closed status.</td></tr><tr><td><code>temperature</code></td><td>Temperature sensors. Displays current temperature and related entities.</td></tr><tr><td><code>humidity</code></td><td>Humidity sensors. Displays current humidity level and related information.</td></tr></tbody></table><h3 id="🪄-pro-ultimate-version-1" tabindex="-1">🪄 <strong>Pro &amp; Ultimate Version</strong> <a class="header-anchor" href="#🪄-pro-ultimate-version-1" aria-label="Permalink to &quot;🪄 **Pro &amp; Ultimate Version**&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Device Type</th><th>Description</th></tr></thead><tbody><tr><td><code>motion</code>, <code>presence</code>, <code>occupancy</code></td><td>Motion or presence sensors. Displays active/inactive state with animated feedback.</td></tr><tr><td><code>door</code></td><td>Door or window contact sensors. Shows open/closed status.</td></tr><tr><td><code>temperature</code></td><td>Temperature sensors. Displays current temperature and related entities.</td></tr><tr><td><code>humidity</code></td><td>Humidity sensors with progress card. Displays current humidity level and related information.</td></tr></tbody></table><div class="note custom-block github-alert"><p class="custom-block-title">NOTE</p><p>🧠 <em>More device classes may be added in future updates.</em></p></div><h2 id="🎨-dialog-features" tabindex="-1">🎨 Dialog Features <a class="header-anchor" href="#🎨-dialog-features" aria-label="Permalink to &quot;🎨 Dialog Features&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Feature</th><th>Description</th></tr></thead><tbody><tr><td><strong>Dynamic Header</strong></td><td>Shows device name, area, and state.</td></tr><tr><td><strong>Animated Status Circle</strong></td><td>Visual indicator (pulsing border) for active sensors.</td></tr><tr><td><strong>Related Entities Section</strong></td><td>Lists all entities associated with the same device (e.g., battery, signal strength).</td></tr><tr><td><strong>Action Menu</strong></td><td>Quick access to “Device Info” and “Related” pages.</td></tr><tr><td><strong>History Button</strong></td><td>Opens Home Assistant’s built-in history panel for the entity.</td></tr><tr><td><strong>Dark/Light Theme Support</strong></td><td>Automatically adapts to HA theme settings.</td></tr><tr><td><strong>Responsive Layout</strong></td><td>Fullscreen modal on mobile devices, centered dialog on desktop.</td></tr></tbody></table><h2 id="💡-example-use-cases" tabindex="-1">💡 Example Use Cases <a class="header-anchor" href="#💡-example-use-cases" aria-label="Permalink to &quot;💡 Example Use Cases&quot;">​</a></h2><ul><li>Tap a <strong>motion sensor</strong> → view detection status, last activity, and related entities.</li><li>Tap a <strong>temperature sensor</strong> → see the current temperature, humidity, and connected devices.</li><li>Tap a <strong>door sensor</strong> → quickly check if a window or door is open.</li></ul><hr><div class="info custom-block"><p class="custom-block-title">⚠️ Notes</p><ul><li>The Material Dialog works only when <code>use_default_toggle: true</code> is enabled. <strong>(Only in the Free version)</strong></li><li>The dialog is automatically managed, no need to specify the type manually.</li><li>If the entity is not one of the supported sensor types, no dialog will open.</li></ul></div>`,37)])])}const b=i(n,[["render",d]]);export{k as __pageData,b as default};
